1	import { quote, claim } from "./claim-office.js";
2	
3	const KNOWN_ITEM_TYPES = new Set([
4	  "sword",
5	  "amulet",
6	  "staff",
7	  "potion",
8	  "rune",
9	  "moonstone",
10	]);
