37	export function runScenario(scenario: any): { results: unknown[] } {
38	  const results: unknown[] = [];
39	  let quoteCount = 0;
40	  const remainingCaps = new Map<number, number>();
41	  for (const step of scenario.steps) {
42	    if (step.op === "quote") {
43	      assertKnownItemTypes(step.items);
44	      const premium = quote({
45	        customer: {
46	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
47	          previousContracts: quoteCount,
48	        },
49	        items: step.items,
50	      });
51	      results.push({ premium });
52	      quoteCount++;
53	    } else if (step.op === "claim") {
54	      const policyStep = scenario.steps[step.policy];
55	      assertDamagesValid(policyStep.items, step.incident.damages);
56	      const { payout, remainingCap } = claim({
57	        items: policyStep.items,
58	        incident: step.incident,
59	        remainingCap: remainingCaps.get(step.policy),
60	      });
61	      remainingCaps.set(step.policy, remainingCap);
62	      results.push({ payout, remainingCap });
63	    }
64	  }
65	  return { results };
66	}
