  const policyItemTypes = policyItems.map((item) => item.type);
  const damageCounts = new Map<string, number>();
  for (const damage of damages) {
    if (!policyItemTypes.includes(damage.itemType)) {
      throw new Error(
        `Claim damages an item not in policy: ${damage.itemType}`,
      );
    }
    if (damage.amount < 0) {
      throw new Error(`Negative damage amount: ${damage.amount}`);
    }
    damageCounts.set(
      damage.itemType,
      (damageCounts.get(damage.itemType) ?? 0) + 1,
    );
  }
  for (const [itemType, count] of damageCounts) {
    const coverageCount = policyItemTypes.filter(
      (type) => type === itemType,
    ).length;
    if (count > coverageCount) {
      throw new Error(`Too many damages for item type: ${itemType}`);
    }
  }
}
